// ─────────────────────────────────────────────────────────────────────
// HELIX admission for the swarm batch boundary
//
// The swarm's batch boundary is `tick_monte_carlo`'s `par_iter_mut`
// call: per round, N agents fan out in parallel and contend on the
// shared topology DAG mutation (reduced through the (u64, [u64; 64])
// `acc` accumulator). Naive dispatch fires all N agents at the same
// instant; HELIX staggers each agent's admission inside a phase-aligned
// corridor so the reduce step never sees the head-of-line pile-up that
// adversarial chaos bursts otherwise produce.
//
// Chaos is unique among FOIL runtimes: its baseline IS adversarial
// perturbation. The naive p99 is therefore catastrophic relative to
// quieter runtimes — and the HELIX win is correspondingly larger,
// because the corridor collapses spike-clusters into bounded waves.
// ─────────────────────────────────────────────────────────────────────

/// True iff the runtime should fall back to the naive (queue-regime)
/// scheduler. Reads the `FOIL_NAIVE` env var; any truthy value (`1`,
/// `true`, `yes`, `on`, case-insensitive) opts out of HELIX. Defaults
/// to `false` — HELIX is the hotpath per
/// `foil-runtime/HELIX_APOTHEOSIS.md`.
///
/// The check is hot-path: env lookup is cheap (a single syscall on
/// Linux, a process-local table walk on macOS) and dominated by the
/// per-tick reduce. We re-read each tick so a long-lived simulation
/// can toggle the mode mid-flight if the operator needs to A/B test.
#[inline]
pub fn foil_naive_enabled() -> bool {
    match std::env::var("FOIL_NAIVE") {
        Ok(v) => {
            let s = v.trim().to_ascii_lowercase();
            matches!(s.as_str(), "1" | "true" | "yes" | "on")
        }
        Err(_) => false,
    }
}

/// Build the per-tick corridor: one [`gnosis_helix::Stoplight`] per
/// agent, with the green window offset by the agent's id so every
/// agent owns a distinct slot inside the cycle. The corridor cycle
/// equals `agent_count` — every agent gets exactly one tick of green
/// per cycle, the chaos-engine analog of the canonical 1-slot
/// bottleneck used by `gnosis-frf` / `gnosis-uring`.
///
/// `arrival_phase` folds the offset INTO the phase (Lean convention).
/// Choosing `offset = (cycle - agent_id) mod cycle` lands agent `i`'s
/// arrival phase at 0 (the green window's opening) for `start = i`,
/// exactly the stagger that one-service-interval-per-agent demands.
#[inline]
fn build_tick_corridor(agent_count: u32) -> Vec<gnosis_helix::Stoplight> {
    let cycle = agent_count.max(1);
    let green = 1u32;
    (0..agent_count)
        .map(|i| {
            let offset = (cycle - i) % cycle;
            gnosis_helix::Stoplight::new(cycle, green, offset, 0, 1)
        })
        .collect()
}

/// HELIX admission for one swarm tick. Returns the earliest start
/// tick (in `[0, cycle)`) at which every agent in the corridor sees
/// green simultaneously — i.e. the earliest moment the batch dispatch
/// can fire without piling agents on the same slot.
///
/// For the canonical staggered corridor built by [`build_tick_corridor`]
/// the corridor-all-green start is `0` by construction (each agent's
/// `offset` was chosen so phase 0 lands inside its own green window).
/// We still call [`gnosis_helix::corridor_all_green`] on every tick so
/// the Lean predicate is the witness, not a comment claim. The cost
/// is `O(N)` per tick — negligible against the per-agent Monte Carlo
/// work that dominates each round.
#[inline]
fn helix_admit_tick(lights: &[gnosis_helix::Stoplight]) -> u32 {
    // Scan one cycle. The canonical stagger lands the corridor green
    // at start=0; an adversarial perturbation that misshapes the
    // corridor would push the first all-green window forward.
    let cycle = lights.first().map(|l| l.cycle).unwrap_or(1);
    let mut t: u32 = 0;
    while t < cycle {
        if gnosis_helix::corridor_all_green(t, lights) {
            return t;
        }
        t += 1;
    }
    0
}

/// The Weyl/Kronecker conjugate multiplier (Golden Ratio inverse).
/// Provides an exact aperiodic uniform distribution.
pub const WEYL_MULTIPLIER: u64 = 0x9E3779B97F4A7C15;

#[inline(always)]
pub fn weyl_next(n: &mut u64) -> u64 {
    let val = n.wrapping_mul(WEYL_MULTIPLIER);
    *n = n.wrapping_add(1);
    val
}

#[inline(always)]
pub fn weyl_gen_range(n: &mut u64, low: u32, high: u32) -> u32 {
    let span = high - low;
    low + (weyl_next(n) % span as u64) as u32
}

#[inline(always)]
pub fn weyl_gen_bool(n: &mut u64, probability: f64) -> bool {
    let max = std::u64::MAX as f64;
    let threshold = (max * probability) as u64;
    weyl_next(n) < threshold
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SwarmAgent {
    pub id: u32,
    pub energy: i64,
    pub node_id: u16,
    pub lifetime_ticks: u64,
    pub rejections: u64,
    pub total_successes: u64,
    pub total_failures: u64,
}

impl SwarmAgent {
    pub fn new(id: u32, energy: i64) -> Self {
        Self {
            id,
            energy,
            node_id: 0,
            lifetime_ticks: 0,
            rejections: 0,
            total_successes: 0,
            total_failures: 0,
        }
    }

    /// The God Formula: w = R - min(v, R) + 1
    #[inline(always)]
    fn buleyean_weight(&self) -> u64 {
        let r = self.energy.max(1) as u64;
        let v = self.rejections;
        r.saturating_sub(v.min(r)) + 1
    }

    #[inline(always)]
    fn resolve_encounter_local(&mut self, n: &mut u64, difficulty: u32, config: &ChaosConfig) {
        let w = self.buleyean_weight();
        let d = difficulty as u64;
        let ratio = w as f64 / (w + d + 1) as f64;
        let threshold_scaled = (ratio * 100_000.0) as u64;

        if (weyl_next(n) % 100_000) < threshold_scaled {
            let absorbed = (d as f64 * config.yield_ratio) as i64 + 1;
            self.energy += absorbed;
            self.total_successes += 1;
        } else {
            self.rejections += 1;
            self.total_failures += 1;
            let penalty = (d as f64 * config.penalty_ratio) as i64 + 10;
            self.energy -= penalty;
        }

        let p = threshold_scaled as f64 / 100_000.0;
        let p_clamped = p.max(0.001).min(0.999);
        let shannon_h =
            -(p_clamped * p_clamped.log2() + (1.0 - p_clamped) * (1.0 - p_clamped).log2());
        self.energy -= (shannon_h * config.shannon_scale) as i64;
    }
}

