const STATIC_SERVER_TOPOLOGY_FINGERPRINT: u64 = 0x8F7E_21C4_9D13_AA06;
const RESIDENT_MANIFOLD_CACHE_CAPACITY: usize = 64;

/// Per-entry metadata for the liquid-memory density eviction policy.
///
/// `density = value_proxy × (hit_count + 1)`
///
/// `value_proxy` is the original `duration_ms` of the cached computation:
/// how many milliseconds would be spent recomputing this result. A long
/// computation that has been hit many times has the highest density and is
/// the last to be evicted under memory pressure.
#[derive(Debug, Clone)]
struct CacheEntry {
    output: ManifoldOutput,
    /// Original wall-clock milliseconds for this computation (the "value"
    /// of keeping this result cached).
    value_proxy: u64,
    /// Number of times this entry has been returned as a cache hit.
    hit_count: u64,
}

impl CacheEntry {
    fn new(output: ManifoldOutput) -> Self {
        let value_proxy = output.duration_ms.max(1);
        Self {
            output,
            value_proxy,
            hit_count: 0,
        }
    }

    /// Liquid-memory density: `value_proxy × (hit_count + 1)`.
    fn density(&self) -> u64 {
        self.value_proxy.saturating_mul(self.hit_count.saturating_add(1))
    }
}

/// Resident manifold cache with liquid-memory density-based eviction.
///
/// When the cache exceeds `RESIDENT_MANIFOLD_CACHE_CAPACITY`, the entry
/// with the *lowest density* is evicted — not the oldest (FIFO) or least
/// recently used (LRU). This preserves computationally expensive results
/// that are frequently accessed while discarding cheap/rare results first.
///
/// `heat_released` accumulates the total density discarded across all
/// evictions for the lifetime of the cache instance.
#[derive(Debug, Default)]
struct ResidentManifoldCache {
    /// Insertion-order deque retained only as a fast "full scan" seed;
    /// eviction no longer pops the front — it finds the minimum-density key.
    order: VecDeque<u64>,
    entries: HashMap<u64, CacheEntry>,
    /// Total density discarded across all evictions (heat released by the
    /// liquid memory as entries boil off).
    pub heat_released: u64,
}

#[derive(Clone, Debug, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct ResidentManifoldCacheSnapshot {
    pub entries: usize,
    pub memory_pressure: u8,
    pub heat_released: u64,
}

impl ResidentManifoldCache {
    fn get(&mut self, key: u64) -> Option<ManifoldOutput> {
        if let Some(entry) = self.entries.get_mut(&key) {
            entry.hit_count = entry.hit_count.saturating_add(1);
            Some(entry.output.clone())
        } else {
            None
        }
    }

    /// Current memory pressure as a value in `0..=100`.
    ///
    /// 0   = empty cache.
    /// 100 = cache is at or above capacity.
    fn memory_pressure(&self) -> u8 {
        let len = self.entries.len();
        if len == 0 {
            return 0;
        }
        let ratio = len as f64 / RESIDENT_MANIFOLD_CACHE_CAPACITY as f64;
        (ratio * 100.0).min(100.0) as u8
    }

    fn insert(&mut self, key: u64, output: ManifoldOutput) {
        if !self.entries.contains_key(&key) {
            self.order.push_back(key);
        }
        self.entries.insert(key, CacheEntry::new(output));

        // Evict until we are within capacity, always removing the lowest-density
        // entry (liquid memory: cold/cheap results boil off first).
        while self.entries.len() > RESIDENT_MANIFOLD_CACHE_CAPACITY {
            // Find the key with the minimum density.
            let victim = self
                .order
                .iter()
                .filter_map(|k| self.entries.get(k).map(|e| (*k, e.density())))
                .min_by_key(|(_, d)| *d)
                .map(|(k, _)| k);

            if let Some(victim_key) = victim {
                if let Some(evicted) = self.entries.remove(&victim_key) {
                    self.heat_released = self
                        .heat_released
                        .saturating_add(evicted.density());
                }
                self.order.retain(|k| *k != victim_key);
            } else {
                // Safety fallback: order is empty but entries is not — clear.
                self.entries.clear();
                break;
            }
        }
    }

    fn snapshot(&self) -> ResidentManifoldCacheSnapshot {
        ResidentManifoldCacheSnapshot {
            entries: self.entries.len(),
            memory_pressure: self.memory_pressure(),
            heat_released: self.heat_released,
        }
    }
}

static RESIDENT_MANIFOLD_CACHE: OnceLock<Mutex<ResidentManifoldCache>> = OnceLock::new();

fn resident_manifold_cache() -> &'static Mutex<ResidentManifoldCache> {
    RESIDENT_MANIFOLD_CACHE.get_or_init(|| Mutex::new(ResidentManifoldCache::default()))
}

#[inline(always)]
fn stable_cache_hash(bytes: &[u8]) -> u64 {
    let mut h = 0xCBF2_9CE4_8422_2325u64;
    for b in bytes {
        h ^= *b as u64;
        h = h.wrapping_mul(0x1000_0000_01B3);
    }
    h
}

fn resident_manifold_cache_key(input: &ManifoldInput) -> Option<u64> {
    let mut canonical = serde_json::to_vec(input).ok()?;
    canonical.extend_from_slice(&STATIC_SERVER_TOPOLOGY_FINGERPRINT.to_le_bytes());
    Some(stable_cache_hash(&canonical))
}

fn mark_resident_manifold_cache_hit(mut output: ManifoldOutput, key: u64) -> ManifoldOutput {
    output.duration_ms = 0;
    output.cache_hit = true;
    output.cache_key = Some(format!("{key:016x}"));
    output
}

fn mark_resident_manifold_cache_miss(mut output: ManifoldOutput, key: u64) -> ManifoldOutput {
    output.cache_hit = false;
    output.cache_key = Some(format!("{key:016x}"));
    output
}

fn is_false(v: &bool) -> bool {
    !*v
}

pub fn resident_manifold_cache_snapshot() -> Option<ResidentManifoldCacheSnapshot> {
    resident_manifold_cache()
        .lock()
        .ok()
        .map(|cache| cache.snapshot())
}

#[inline(always)]
fn count_components(nodes: u64, edges: &[u64; 64]) -> u64 {
    let mut parent = [0u8; 64];
    for i in 0..64 {
        parent[i] = i as u8;
    }

    let find = |mut i: u8, p: &mut [u8; 64]| -> u8 {
        while p[i as usize] != i {
            p[i as usize] = p[p[i as usize] as usize];
            i = p[i as usize];
        }
        i
    };

    for i in 0..64 {
        if (nodes & (1 << i)) != 0 {
            let mut edge_mask = edges[i];
            while edge_mask != 0 {
                let j = edge_mask.trailing_zeros() as u8;
                if (nodes & (1 << j)) != 0 {
                    let root_i = find(i as u8, &mut parent);
                    let root_j = find(j, &mut parent);
                    if root_i != root_j {
                        parent[root_i as usize] = root_j;
                    }
                }
                edge_mask &= edge_mask - 1;
            }
        }
    }

    let mut root_mask = 0u64;
    for i in 0..64 {
        if (nodes & (1 << i)) != 0 {
            let r = find(i as u8, &mut parent);
            root_mask |= 1 << r;
        }
    }

    root_mask.count_ones() as u64
}

impl ChaosEngine {
    pub fn new(seed: u64, config: ChaosConfig, topology: &Topology) -> Self {
        let agent_count = config.agent_count;
        let mut agents = Vec::with_capacity(agent_count as usize);

        let max_node_id = topology.nodes.iter().map(|n| n.id).max().unwrap_or(0) as usize;
        let mut node_ops = vec![NodeOp::Accept; max_node_id + 1];
        let mut edge_map = vec![Vec::new(); max_node_id + 1];

        for node in topology.nodes {
            node_ops[node.id as usize] = node.op;
        }
        for edge in topology.edges {
            edge_map[edge.from as usize].push((edge.to.to_vec(), edge.edge_type));
        }

        let mut seed_n = seed;
        for i in 0..agent_count {
            let energy = 1000 + (weyl_next(&mut seed_n) % 500) as i64;
            agents.push(SwarmAgent::new(i, energy));
        }

        Self {
            metrics: UniverseBenchmarkMetrics {
                universe_seed: seed,
                total_agent_population: agent_count,
                ..Default::default()
            },
            agents,
            clinamen_pressure: 1,
            config,
            node_ops,
            edge_map,
        }
    }

    fn self_tune(&mut self) {
        let active_survivors = self.agents.iter().filter(|a| a.energy > 0).count();
        let current_rate = active_survivors as f64 / self.metrics.total_agent_population as f64;
        let gap = (current_rate - self.config.target_survival_rate).abs();
        let step = if gap > 0.1 { 5 } else { 1 };

        if current_rate > self.config.target_survival_rate {
            self.clinamen_pressure += step;
        } else if current_rate < self.config.target_survival_rate && self.clinamen_pressure >= step
        {
            self.clinamen_pressure -= step;
        } else if current_rate < self.config.target_survival_rate {
            self.clinamen_pressure = 0;
        }
    }

    pub fn tick_monte_carlo(&mut self, rounds: u32) {
        // HELIX corridor for this engine's agent population. Built once
        // (cycle = agent_count) and reused per tick: the corridor shape
        // is a property of the agent set, not of the tick. Skipped when
        // `FOIL_NAIVE=1` — in that mode the loop runs exactly the
        // legacy rayon-style fast path.
        //
        // Default = HELIX per `foil-runtime/HELIX_APOTHEOSIS.md` "The
        // standard (enforced, not suggested)" item 2: every primitive
        // entry point routes through `corridor_all_green` admission.
        let helix_enabled = !foil_naive_enabled();
        let corridor: Vec<gnosis_helix::Stoplight> = if helix_enabled {
            build_tick_corridor(self.agents.len() as u32)
        } else {
            Vec::new()
        };

        for round in 1..=rounds {
            if round % 100 == 0 {
                self.self_tune();
            }

            // HELIX admission gate. The corridor predicate is the Lean
            // `corridorAllGreen` (per gnosis-helix), pinned to the
            // staggered Stoplight set we built above. The canonical
            // stagger lands all-green at start=0, so this is a
            // single-iteration scan in the steady state — but if a
            // chaos perturbation ever drove the corridor red, the gate
            // would advance the dispatch to the next green slot rather
            // than pile the swarm on a contended phase. `FOIL_NAIVE=1`
            // skips the gate entirely and falls through to the legacy
            // par_iter_mut path.
            if helix_enabled {
                let _admit_tick = helix_admit_tick(&corridor);
                // _admit_tick is the start phase the corridor authorized.
                // In the canonical staggered shape it is always 0; we
                // intentionally don't busy-wait on it here because the
                // per-tick reduce is the implicit synchronization point
                // (analogous to the bottleneck drain in gnosis-frf). The
                // gate's load-bearing role is to RUN corridor_all_green
                // every tick — the predicate's success IS the admission.
                // Note: per-agent time-based gating runs inside the par_iter
                // closure and is independent of this tick-level corridor check.
            }

            let config = self.config;
            let node_ops = &self.node_ops;
            let edge_map = &self.edge_map;
            let total_agents = self.agents.len() as u64;
            let clinamen_pressure = self.clinamen_pressure;

            // Per-perturbation HELIX admission: track batch start and per-agent
            // service time so the polyglot admission module can stagger individual
            // agents inside the reduce window. Service time estimate: 50us per
            // agent for typical node operation + accumulator merge.
            // Note: per-agent ID serves as index since agents are stored in ID order.
            let batch_start = Instant::now();
            let service_time_us = 50u64;

            let (global_nodes, global_edges) = self
                .agents
                .par_iter_mut()
                .map(|agent| {
                    let mut acc = (0u64, [0u64; 64]);
                    if agent.energy <= 0 {
                        return acc;
                    }

                    // Per-perturbation HELIX admission check: admit this agent
                    // only after the admission window for its index has opened.
                    // Uses the polyglot time-based staggering that gates work
                    // by elapsed time + agent index + service time estimate.
                    // Spin-waits if gated; bounded in duration by the corridor
                    // architecture. In serial regimes, gates are disabled via
                    // HELIX_GATE_STRATEGY env var (default).
                    while !helix_admission::admit(batch_start, agent.id as u64, service_time_us) {
                        std::hint::spin_loop();
                    }

                    // Purely functional aperiodic sequence state for this exact agent and tick
                    let mut weyl_state = (round as u64)
                        .wrapping_mul(total_agents)
                        .wrapping_add(agent.id as u64);

                    let v = agent.rejections;
                    let c = 1000.0_f64;
                    let gamma = 1.0 / (1.0 - (v as f64 / c).min(0.999_f64).powi(2)).sqrt();
                    agent.energy -= (clinamen_pressure as f64 * gamma) as i64;
                    agent.lifetime_ticks += 1;

                    if agent.energy <= 0 {
                        return acc;
                    }

                    if agent.lifetime_ticks > config.fatigue_threshold as u64 {
                        let fatigue = (agent.lifetime_ticks as f64
                            / config.fatigue_threshold as f64)
                            .powi(2) as i64;
                        agent.energy -= fatigue;
                    }

                    if weyl_gen_bool(&mut weyl_state, config.black_hole_chance) {
                        if agent.energy > 1000 {
                            agent.energy -= 800;
                        } else {
                            agent.energy = 0;
                            return acc;
                        }
                    }

                    let current_node_id = agent.node_id;
                    let op = node_ops[current_node_id as usize];
                    match op {
                        NodeOp::Accept => {}
                        NodeOp::ParseHttp => {
                            agent.energy -= 50;
                        }
                        NodeOp::CacheLookup => {
                            agent.resolve_encounter_local(&mut weyl_state, 80, &config);
                        }
                        NodeOp::MmapRead => {
                            agent.resolve_encounter_local(&mut weyl_state, 200, &config);
                        }
                        NodeOp::DiskRead => {
                            agent.resolve_encounter_local(&mut weyl_state, 500, &config);
                        }
                        NodeOp::BuildHeaders => {
                            agent.energy -= 30;
                        }
                        _ => {
                            agent.resolve_encounter_local(&mut weyl_state, 100, &config);
                        }
                    }

                    let edges = &edge_map[current_node_id as usize];
                    if edges.is_empty() {
                        agent.node_id = 0;
                        return acc;
                    }

                    let edge_idx =
                        weyl_gen_range(&mut weyl_state, 0u32, edges.len() as u32) as usize;
                    let (to_nodes, edge_type) = &edges[edge_idx];
                    let target_idx =
                        weyl_gen_range(&mut weyl_state, 0u32, to_nodes.len() as u32) as usize;
                    agent.node_id = to_nodes[target_idx];

                    match edge_type {
                        Edge::Fork => {
                            agent.energy -= 5;
                        }
                        Edge::Race => {
                            agent.energy -= 2;
                        }
                        Edge::Fold => {
                            agent.energy += 10;
                        }
                        Edge::Vent => {
                            if weyl_gen_bool(&mut weyl_state, config.vent_fatality) {
                                agent.energy = 0;
                            }
                        }
                        Edge::Delay => {
                            // Delayed projection: cheaper than fork (stays in trit space).
                            // No collapse cost. The mirror absorbs the state.
                            agent.energy -= 1;
                        }
                        Edge::Process => {
                            agent.energy -= 1;
                        }
                    }

                    if current_node_id < 64 && agent.node_id < 64 {
                        acc.0 |= 1 << current_node_id;
                        acc.0 |= 1 << agent.node_id;
                        acc.1[current_node_id as usize] |= 1 << agent.node_id;
                    }

                    acc
                })
                .reduce(
                    || (0u64, [0u64; 64]),
                    |mut a, b| {
                        a.0 |= b.0;
                        for i in 0..64 {
                            a.1[i] |= b.1[i];
                        }
                        a
                    },
                );

            // Compute topological Betti numbers for the active swarm manifold
            let v = global_nodes.count_ones() as u64;
            let mut e = 0u64;
            for i in 0..64 {
                e += global_edges[i].count_ones() as u64;
            }
            let betti_0 = count_components(global_nodes, &global_edges);
            let betti_1 = e + betti_0 - v.min(e + betti_0); // Prevent underflow if V > E+B0 (e.g. v=0)
            self.metrics.betti_0 = betti_0;
            self.metrics.betti_1 = betti_1;
        }

        self.metrics.total_throughput = self.agents.iter().map(|a| a.total_successes).sum();
        self.metrics.total_successful_strikes = self.metrics.total_throughput;
    }
}

// ── FFI Bridge (GnosisRayon) ────────────────────────────────────────

#[derive(Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct ManifoldInput {
    pub seed: u64,
    pub rounds: u32,
    pub config: ChaosConfig,
    /// Optional formal stepwise run (`StepwiseAnalysisFramework.AnalysisCard`
    /// in Lean). When present, a deterministic digest is XOR-mixed into the
    /// engine seed before Monte Carlo ticks.
    #[serde(default)]
    pub analysis_run: Option<Vec<crate::stepwise::AnalysisCard>>,
}

#[derive(Clone, Debug, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct ManifoldOutput {
    pub duration_ms: u64,
    pub metrics: UniverseBenchmarkMetrics,
    pub active_survivors: usize,
    pub clinamen_pressure: i64,
    /// Digest echoed from the input run (same as XOR’d into `seed` when run
    /// was `Some`). `None` if no `analysis_run` was supplied.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub analysis_digest: Option<u64>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub analysis_card_count: Option<u32>,
    /// True when the resident manifold boundary returned a cached deterministic
    /// result for the same canonical input and static topology fingerprint.
    #[serde(default, skip_serializing_if = "is_false")]
    pub cache_hit: bool,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub cache_key: Option<String>,
}

pub fn run_parallel_manifold(input: ManifoldInput) -> ManifoldOutput {
    let analysis_digest = input
        .analysis_run
        .as_ref()
        .filter(|v| !v.is_empty())
        .map(|v| digest_analysis_run(v.as_slice()));
    let mixed_seed = input.seed ^ analysis_digest.unwrap_or(0);

    let mut engine = ChaosEngine::new(mixed_seed, input.config, &crate::topology::STATIC_SERVER);

    let start = std::time::Instant::now();
    engine.tick_monte_carlo(input.rounds);
    let duration_ms = start.elapsed().as_millis() as u64;

    let active_survivors = engine.agents.iter().filter(|a| a.energy > 0).count();

    ManifoldOutput {
        duration_ms,
        metrics: engine.metrics,
        active_survivors,
        clinamen_pressure: engine.clinamen_pressure,
        analysis_digest,
        analysis_card_count: input
            .analysis_run
            .as_ref()
            .filter(|v| !v.is_empty())
            .map(|v| v.len() as u32),
        cache_hit: false,
        cache_key: None,
    }
}

pub fn run_parallel_manifold_resident_cached(input: ManifoldInput) -> ManifoldOutput {
    let Some(key) = resident_manifold_cache_key(&input) else {
        return run_parallel_manifold(input);
    };

    if let Some(hit) = resident_manifold_cache()
        .lock()
        .ok()
        .and_then(|mut cache| cache.get(key))
    {
        return mark_resident_manifold_cache_hit(hit, key);
    }

    let output = run_parallel_manifold(input);
    if let Ok(mut cache) = resident_manifold_cache().lock() {
        cache.insert(key, output.clone());
    }
    mark_resident_manifold_cache_miss(output, key)
}

#[cfg(not(target_arch = "wasm32"))]
#[no_mangle]
pub extern "C" fn tick_parallel_manifold(input_json: *const libc::c_char) -> *mut libc::c_char {
    if input_json.is_null() {
        return std::ptr::null_mut();
    }

    let c_str = unsafe { CStr::from_ptr(input_json) };
    let json_str = match c_str.to_str() {
        Ok(s) => s,
        Err(_) => return std::ptr::null_mut(),
    };

    let input: ManifoldInput = match serde_json::from_str(json_str) {
        Ok(i) => i,
        Err(_) => return std::ptr::null_mut(),
    };

    let output = run_parallel_manifold_resident_cached(input);

    let output_json = match serde_json::to_string(&output) {
        Ok(s) => s,
        Err(_) => return std::ptr::null_mut(),
    };

    let c_output = match CString::new(output_json) {
        Ok(c) => c,
        Err(_) => return std::ptr::null_mut(),
    };

    c_output.into_raw()
}

#[cfg(not(target_arch = "wasm32"))]
#[no_mangle]
pub extern "C" fn free_manifold_string(s: *mut libc::c_char) {
    if s.is_null() {
        return;
    }
    unsafe {
        let _ = CString::from_raw(s);
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn small_input(seed: u64) -> ManifoldInput {
        ManifoldInput {
            seed,
            rounds: 2,
            config: ChaosConfig {
                agent_count: 128,
                ..ChaosConfig::default()
            },
            analysis_run: None,
        }
    }

    #[test]
    fn resident_cache_hits_identical_manifold_input() {
        let first = run_parallel_manifold_resident_cached(small_input(910));
        let second = run_parallel_manifold_resident_cached(small_input(910));

        assert!(!first.cache_hit);
        assert!(second.cache_hit);
        assert_eq!(first.cache_key, second.cache_key);
        assert_eq!(first.metrics, second.metrics);
        assert_eq!(first.active_survivors, second.active_survivors);
        assert_eq!(first.clinamen_pressure, second.clinamen_pressure);
        assert_eq!(second.duration_ms, 0);
    }

    #[test]
    fn resident_cache_misses_changed_seed() {
        let first = run_parallel_manifold_resident_cached(small_input(911));
        let changed = run_parallel_manifold_resident_cached(small_input(912));

        assert!(!first.cache_hit);
        assert!(!changed.cache_hit);
        assert_ne!(first.cache_key, changed.cache_key);
    }
}
